before_script:
mkdir -p reports

test -n "$DOTENV_FILE" || {
  echo '[ERROR] DOTENV_FILE is required'
  exit 1
}
: > "$DOTENV_FILE"

mark() {
  printf '%s\n' "$1" >> "reports/${CI_JOB_NAME}.log"
}

require_env() {
  name="$1"
  eval "value=\${$name:-}"
  test -n "$value" || {
    echo "[ERROR] missing env: $name"
    exit 1
  }
}

reject_env() {
  name="$1"
  eval "is_set=\${$name+x}"
  if [ -n "$is_set" ]; then
    eval "value=\${$name}"
    echo "[ERROR] unexpected env: $name=$value"
    exit 1
  fi
}

export_dotenv() {
  printf '%s=%s\n' "$1" "$2" >> "$DOTENV_FILE"
}

